sql:
SELECT station_name
FROM stations
WHERE status = 'operational';

SELECT city_id, COUNT(station_id) AS number_of_stations
FROM stations
GROUP BY city_id;

SELECT COUNT(station_id) AS operational_stations_count
   FROM stations
   WHERE status = 'operational';

SELECT COUNT(bike_id) AS total_bikes_needing_maintenance
FROM bike_maintenance
WHERE next_maintenance_due <= '2023-05-30';

external_knowledge:
- 'busiest station' refers to the station with the highest sum of available bikes;
- 'total bikes in its city' refers to 'num_bikes' from the city_operations table;
- 'average battery level' is calculated from the electric bikes in the city.

sql:
SELECT user_id, COUNT(feedback_id) AS total_feedback
FROM user_feedback
GROUP BY user_id;

SELECT AVG(available_bikes) AS average_available_bikes
FROM station_status
WHERE status_time BETWEEN datetime('now', '-1 month') AND datetime('now');

SELECT num_bikes AS total_bikes
FROM city_operations
WHERE city_name = 'City B';
